// ============================================================================
// Helper functions
// ============================================================================

export function getCountryById(id: string): Country | undefined {
  return countries.find(c => c.id === id);
}

export function getCountriesByRegion(region: string): Country[] {
  return countries.filter(c => c.region === region);
}

export function getCountriesByRec(rec: string): Country[] {
  return countries.filter(c => c.recs.includes(rec));
}

export function getCountriesByIncome(level: string): Country[] {
  return countries.filter(c => c.incomeLevel === level);
}

export function searchCountries(query: string): Country[] {
  const q = query.toLowerCase();
  return countries.filter(c =>
    c.name.toLowerCase().includes(q) ||
    c.fullName.toLowerCase().includes(q)
  );
}

export function getAllCountriesAlphabetical(): Country[] {
  return [...countries].sort((a, b) => a.name.localeCompare(b.name));
}
